import { useState, memo } from 'react';
import cls from './Register.module.scss';
import { isMobile } from 'react-device-detect';
import { Button, FieldRow, TaskBoardPanel } from '../../common';
import MessageContainer from '../ProcessesComps/MessageContainer/MessageContainer';
import { createNewCompany } from '../../../services/company.service';
import { take } from 'rxjs';
import { store } from '../../../reduxStore/store';
import { setMessageBar } from '../../../reduxStore/actions/flowActions';
import { APP_NAME } from '../../../shared/utility';
import { useNavigate } from 'react-router-dom';
import MessageBar from '../../TopBar/MessageBar';
import { useSelector } from 'react-redux';

const Register = memo(() => {
	const [newCompany, setNewCompany] = useState({ message: '' });
	const { showMessage } = useSelector(store => store.flowReducer);
	const { authenticated } = useSelector(store => store.authReducer);

	const [loading, setLoading] = useState(false);
	const navigate = useNavigate();
	const createCompany = () => {
		if (newCompany.companyName && newCompany.displayName && newCompany.email && newCompany.firstName && newCompany.lastName && newCompany.slug) {
			setLoading(true);
			createNewCompany(newCompany)
				.pipe(take(1))
				.subscribe({
					next: () => store.dispatch(setMessageBar({ noTimeout: true, show: true, message: `We have received your request for the creation of ${newCompany.companyName}. We will gladly review this. We will send an email notification to ${newCompany.email}`, action: () => navigate('/login') })),
					error: () => {
						setLoading(false);
						store.dispatch(setMessageBar({ show: true, message: `Fail! There is something wrong with the details you provided`, color: 'red', action: () => store.dispatch(setMessageBar({ show: false, message: `` })) }));
					},
					complete: () => setLoading(false),
				});
		}
	};

	const renderSuperAdminCreateCompany = () => {
		return (
			<div>
				<FieldRow fieldLabel={'Company Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, companyName: e.target.value, displayName: e.target.value, slug: e.target.value.replace(' ', '').toLowerCase() });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Company Name'}
						/>
					</div>
				</FieldRow>

				<FieldRow fieldLabel={'Email'} style={{ border: '0', width: '100%' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, email: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Email'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'First Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, firstName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'First Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Last Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, lastName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Last Name'}
						/>
					</div>
				</FieldRow>
			</div>
		);
	};

	return (
		<div style={{}}>
			<p
				onClick={() => navigate('/')}
				style={{
					cursor: 'pointer',
					fontFamily: 'var(--app-text-main-font)',
					color: '#4A4A4A',
					textDecoration: 'underline',
					paddingLeft: '10px',
					display: isMobile ? 'none' : '',
				}}
			>
				Home
			</p>
			{showMessage?.show && !authenticated && <MessageBar />}
			<div style={{ margin: 'auto', marginTop: '100px', width: isMobile ? '120%' : '40%', minWidth: '400px' }}>
				{newCompany?.message !== '' && <MessageContainer message={newCompany?.message} onClick={() => setNewCompany({ ...newCompany, message: '' })} />}
				<TaskBoardPanel cardTitle={`Registration Form`}>{renderSuperAdminCreateCompany()}</TaskBoardPanel>
				<div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', margin: '20px' }}>
					<Button clicked={createCompany} title={'Sign me up'} loading={loading} />
				</div>
			</div>
		</div>
	);
});

export default Register;
